changeSet.sql:
-- Добавить новую колонку
ALTER TABLE generation_batches
    ADD COLUMN overwrite_duplicates BOOLEAN NOT NULL DEFAULT false;

-- Перенести данные: OVERWRITE → true, SKIP → false
UPDATE generation_batches SET overwrite_duplicates = true WHERE dedupe_mode = 'OVERWRITE';

-- Удалить старую колонку и constraint
ALTER TABLE generation_batches DROP CONSTRAINT IF EXISTS ck_batches_dedupe;
ALTER TABLE generation_batches DROP COLUMN dedupe_mode;

-- Перевести существующие SKIPPED в DONE (они были дубликатами, asset уже существовал)
UPDATE generation_requests SET status = 'DONE' WHERE status = 'SKIPPED';

-- Обновить constraint на статус
ALTER TABLE generation_requests DROP CONSTRAINT IF EXISTS ck_requests_status;
ALTER TABLE generation_requests
    ADD CONSTRAINT ck_requests_status
    CHECK (status IN ('PENDING', 'RUNNING', 'DONE', 'FAILED'));
